import React, { useState, useEffect } from "react";
import { Link, NavLink, useNavigate } from "react-router-dom";
import "../styles/Header.css";

export const HeaderComponent = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const navigate = useNavigate();

  // Verificar autenticación al cargar el componente (ej: si hay token en localStorage)
  useEffect(() => {
    const token = localStorage.getItem("authToken");
    if (token) {
      setIsLoggedIn(true);
    }
  }, []);

  const handleLogin = () => {
    if (isLoggedIn) {
      // Cerrar sesión
      localStorage.removeItem("authToken");
      setIsLoggedIn(false);
    } else {
      // Redirigir a la página de login
      navigate("/login");
    }
  };

  return (
    <header className="header-pastel">
      <div className="container">
        <nav className="nav-main">
          <Link to="/" className="brand">
            <span className="logo">🍰</span>
            <span className="brand-name">Como En Casa</span>
          </Link>

          <ul className="nav-links">
            <li>
              <NavLink to="/" end>
                Inicio
              </NavLink>
            </li>
            <li>
              <NavLink to="/pasteles">Pasteles</NavLink>
            </li>
            <li>
              <NavLink to="/postres">Postres</NavLink>
            </li>
            <li>
              <NavLink to="/eventos">Eventos</NavLink>
            </li>
            <li>
              <NavLink to="/nosotros">Nosotros</NavLink>
            </li>
          </ul>

          <div className="nav-actions">
            <button onClick={handleLogin} className="login-button">
              {isLoggedIn ? "👤 Cerrar Sesión" : "Iniciar Sesión"}
            </button>
            <Link to="/carrito" className="cart-icon">
              🛒
            </Link>
          </div>
        </nav>
      </div>
    </header>
  );
};
